def test_individual_mention_in_top_level_channel_fires_all_four_surfaces():
    """REQ-001: WHEN @-mention of channel member → push+banner+sound+badge fire."""
    member = make_member("m1")
    channel = make_channel("c1", member_ids=("m1", "m99"))
    message = make_message(channel=channel, author_id="m99", mentions=("m1",))

    push, banner, sound, badge = PushSurface(), InAppBannerSurface(), SoundSurface(), UnreadBadgeSurface()
    event = make_event(member_id="m1", message=message)

    result = DispatchMentionNotification(
        member=member, event=event,
        surfaces=(push, banner, sound, badge),
        dnd=make_dnd(),  # no DND
    )

    assert push.fired_for(event)
    assert banner.fired_for(event)
    assert sound.fired_for(event)
    assert badge.incremented_for(event)
    assert result.delivered is True


def test_mention_event_is_delivered_when_only_one_surface_succeeds():
    """REQ-001: event SHALL be considered delivered when ≥1 surface fires."""
    member = make_member("m1")
    event = make_event(member_id="m1")
    # Three surfaces deliberately fail; one succeeds.
    failing_push = PushSurface(fail=True)
    failing_banner = InAppBannerSurface(fail=True)
    failing_sound = SoundSurface(fail=True)
    working_badge = UnreadBadgeSurface()

    result = DispatchMentionNotification(
        member=member, event=event,
        surfaces=(failing_push, failing_banner, failing_sound, working_badge),
        dnd=make_dnd(),
    )

    assert result.delivered is True
    assert result.successful_surfaces == {"unread_badge"}


