def test_in_thread_mention_to_non_participant_is_silently_skipped():
    """REQ-001 constraint: in a thread, non-participants are silently skipped."""
    parent = make_channel("c1", member_ids=("m1", "m2", "m3"))
    thread = make_channel("t1", member_ids=("m1", "m2", "m3"), is_thread=True, parent=parent)
    thread.thread_participants = {"m1"}  # only m1 has posted in the thread
    message = make_message(channel=thread, author_id="m99", mentions=("m2",))

    recipients = ResolveMentionRecipients(message)
    assert recipients == []  # m2 has never posted → skipped silently


