@st.composite
def channels_with_members(draw):
    n = draw(st.integers(min_value=2, max_value=6))
    member_ids = [f"m{i}" for i in range(n)]
    return make_channel("c1", member_ids=tuple(member_ids))


@st.composite
def events_for_channel(draw):
    channel = draw(channels_with_members())
    mentioner = draw(st.sampled_from(list(channel.member_ids)))
    candidates = [m for m in channel.member_ids if m != mentioner]
    mentioned = draw(st.sampled_from(candidates))
    message = make_message(channel=channel, author_id=mentioner, mentions=(mentioned,))
    return make_event(member_id=mentioned, message=message), channel, mentioned


# Idempotent: repeated dispatch on the same event must produce one observable
# notification — push.fired_for stays true; counters do not double.
@settings(max_examples=500, deadline=None)
@given(events_for_channel())
def test_mention_pipeline_is_idempotent_on_repeated_dispatch_for_same_event(payload):
    """Property: idempotent (REQ-001). dispatch(dispatch(e)) ≡ dispatch(e)."""
    event, channel, mentioned_id = payload
    member = make_member(mentioned_id)
    push, banner, sound, badge = PushSurface(), InAppBannerSurface(), SoundSurface(), UnreadBadgeSurface()
    surfaces = (push, banner, sound, badge)
    dnd = make_dnd()

    DispatchMentionNotification(member=member, event=event, surfaces=surfaces, dnd=dnd)
    snap1 = (
        push.fire_count_for(event),
        banner.fire_count_for(event),
        sound.fire_count_for(event),
        badge.increment_count_for(event),
    )
    DispatchMentionNotification(member=member, event=event, surfaces=surfaces, dnd=dnd)
    snap2 = (
        push.fire_count_for(event),
        banner.fire_count_for(event),
        sound.fire_count_for(event),
        badge.increment_count_for(event),
    )

    assert snap1 == snap2, f"dispatch was not idempotent: {snap1} != {snap2}"


# Monotonic: under DND, badge count only ever increases as mentions arrive.
@settings(max_examples=500, deadline=None)
@given(st.lists(events_for_channel(), min_size=1, max_size=20))
def test_unread_badge_count_is_monotonic_under_dnd(events):
    """Property: monotonic (REQ-002). Under DND, badge count never decreases."""
    member = make_member("m_target")
    badge = UnreadBadgeSurface()
    dnd = make_dnd(manual_on=True)

    prev = badge.unread_mention_count_for(member)
    for event, _, _ in events:
        # rebind the event to our target member for this test
        event.mentioned_id = "m_target"
        DispatchMentionNotification(
            member=member, event=event,
            surfaces=(PushSurface(), InAppBannerSurface(), SoundSurface(), badge),
            dnd=dnd,
        )
        cur = badge.unread_mention_count_for(member)
        assert cur >= prev, f"badge count decreased: {prev} → {cur}"
        prev = cur


# Invariant: while DND active, push / banner / sound must never fire.
@settings(max_examples=500, deadline=None)
@given(st.lists(events_for_channel(), min_size=1, max_size=20))
def test_dnd_silence_invariant_no_push_banner_sound_while_dnd_active(events):
    """Property: invariant (REQ-002). DND-active → 0 push/banner/sound fires."""
    member = make_member("m_target")
    push, banner, sound, badge = PushSurface(), InAppBannerSurface(), SoundSurface(), UnreadBadgeSurface()
    dnd = make_dnd(manual_on=True)

    for event, _, _ in events:
        event.mentioned_id = "m_target"
        DispatchMentionNotification(
            member=member, event=event,
            surfaces=(push, banner, sound, badge), dnd=dnd,
        )

    assert push.total_fire_count() == 0
    assert banner.total_fire_count() == 0
    assert sound.total_fire_count() == 0


# Invariant: mention to non-member of channel → zero surfaces fire (REQ-003).
@settings(max_examples=500, deadline=None)
@given(channels_with_members(), st.text(min_size=2, max_size=8))
def test_non_member_mention_invariant_zero_surfaces_fire(channel, outsider_id):
    """Property: invariant (REQ-003). Non-member mention → 0 surfaces fire."""
    if outsider_id in channel.member_ids:
        return  # generator produced an in-channel id; skip — vacuously true
    message = make_message(channel=channel, author_id=next(iter(channel.member_ids)), mentions=(outsider_id,))
    candidates = ResolveMentionRecipients(message)
    filtered = FilterIneligibleRecipients(candidates, channel=channel, mentioner_id=message.author_id)
    assert filtered == []


